import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.Reader;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private Path mockPath;
    private Charset charset;
    private CSVFormat format;
    private Reader mockedReader;

    @BeforeEach
    void setup() {
        mockPath = mock(Path.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);
        mockedReader = mock(Reader.class);
    }

    @Test
    void parse_withValidPath_callsFilesNewBufferedReaderAndParse() throws Exception {
        try (MockedStatic<Files> filesStatic = Mockito.mockStatic(Files.class);
             MockedStatic<CSVParser> parserStatic = Mockito.mockStatic(CSVParser.class)) {
            filesStatic.when(() -> Files.newBufferedReader(mockPath, charset)).thenReturn(mockedReader);
            CSVParser expectedParser = mock(CSVParser.class);
            parserStatic.when(() -> CSVParser.parse(mockedReader, format)).thenReturn(expectedParser);

            CSVParser actualParser = CSVParser.parse(mockPath, charset, format);

            assertSame(expectedParser, actualParser);
            filesStatic.verify(() -> Files.newBufferedReader(mockPath, charset));
            parserStatic.verify(() -> CSVParser.parse(mockedReader, format));
        }
    }

    @Test
    void parse_withNullPath_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((Path) null, charset, format));
        assertEquals("path", ex.getMessage());
    }

    @Test
    void parse_withNullFormat_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockPath, charset, null));
        assertEquals("format", ex.getMessage());
    }

}
